content:
/* File chips */
  #file-chips{display:flex;flex-wrap:wrap;gap:6px;padding:0}
  #file-chips:empty{display:none}
  .file-chip{display:inline-flex;align-items:center;gap:4px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:3px 8px;font-size:12px;color:var(--accent)}
  .file-chip img{height:28px;width:28px;object-fit:cover;border-radius:4px}
  .file-chip button{background:none;border:none;color:var(--err);cursor:pointer;font-size:14px;padding:0 2px;line-height:1}
  .chat-img{max-width:300px;max-height:200px;border-radius:8px;margin:4px 0;display:block}

  /* File links */
  .file-links{display:flex;flex-wrap:wrap;gap:6px;margin-top:8px;padding-top:8px;border-top:1px solid var(--border)}
  .file-link{display:inline-flex;align-items:center;gap:4px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:4px 10px;font-size:12px;color:var(--accent);text-decoration:none;cursor:pointer;transition:background .15s,border-color .15s}
  .file-link:hover{background:var(--hover);border-color:var(--accent)}
  .file-link .fl-icon{font-size:14px}
  .file-link .fl-name{max-width:280px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
